sql:
SELECT transaction_date, event_description, debit_amount
FROM transactions
WHERE transaction_type = 'Invoice' OR transaction_type = 'Payment';

SELECT AVG(credit_amount) 
FROM transactions 
WHERE invoice_id IN (
    SELECT invoice_id 
    FROM invoices 
    WHERE total_amount > (
        SELECT AVG(total_amount) 
        FROM invoices
    )
);

SELECT invoices.invoice_id, accounts.account_id
FROM invoices
JOIN accounts ON invoices.customer_id = accounts.account_id;

SELECT quantity, unit_price, total_price, tax_amount, currency
FROM invoice_items
WHERE invoice_item_id = 0;

SELECT invoices.invoice_id, transactions.transaction_type
FROM invoices 
INNER JOIN transactions ON invoices.invoice_id = transactions.invoice_id;

external_knowledge:
- "gardeners" refers to the users who have conducted transactions;
- "seeds" symbolize the products involved in the transactions;
- "average sunlight and water" metaphorically represents the average debit and credit amounts;
- "blooming year" refers to the transactions that happened in the year 2023;
- "nurtured more than ten types of seeds" refers to users who have more than ten transactions.
